args.sparql:
SELECT ?seasonLabel WHERE {
  wd:Q183513 wdt:P361 ?season.
  ?season rdfs:label ?seasonLabel.
  FILTER (lang(?seasonLabel) = "en")
}

SELECT ?episodeLabel WHERE {
  wd:Q2715602 wdt:P361 ?episode .
  ?episode wdt:P366 "1" .
  ?episode rdfs:label ?episodeLabel .
  FILTER (lang(?episodeLabel) = "en")
}

SELECT ?episodeLabel WHERE {
  wd:Q2715602 wdt:P361 ?episode .
  ?episode wdt:P366 1 .
  ?episode rdfs:label ?episodeLabel .
  FILTER (lang(?episodeLabel) = "en")
}

SELECT ?episodeLabel WHERE {
  wd:Q2715602 wdt:P361 ?episode.
  ?episode rdfs:label ?episodeLabel.
  FILTER (lang(?episodeLabel) = "en" && ?episodeLabel = "Welcome to the Hellmouth")
}
